def docstring(sym):
    "Get docstring for `sym` for functions ad classes"
    if isinstance(sym, str): return sym
    res = getdoc(sym)
    if not res and isclass(sym): res = getdoc(sym.__init__)
    if not res and callable(sym) and not isclass(sym): res = getdoc(sym.__call__)
    return res or ""

